mapper.select:
select  from `order`


        and member_id = #{param.memberId}


        and mobile = #{param.mobile}


        and user_name = #{param.userName}


        and store_id = #{param.storeId}


        and order_code = #{param.orderCode}


        and cancel = #{param.cancel}


        and order_status = #{param.orderStatus}


        and   pay_time <= #{param.payTime} 


        and   order_time <= #{param.orderTime} 


order by create_time desc

SELECT order_status, COUNT(*) AS order_num
FROM `order` where member_id=#{memberId}
GROUP BY order_status;

select,
member.mobile,
member.user_name
from `order`
left join member on member.id = `order`.member_id


        and `order`.member_id = #{param.memberId}


        and member.mobile = #{param.mobile}


        and member.user_name = #{param.userName}


        and `order`.store_id = #{param.storeId}


        and `order`.order_code = #{param.orderCode}


        and `order`.order_status = #{param.orderStatus}


order by create_time desc
